// --- types.d.ts ---
import { ReactNode } from 'react';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F' | string;
  forecast: ForecastItem[];
}

export interface ForecastDayProps {
  day: string;
  icon: string;
  high: number;
  low: number;
  unit: string;
}

export interface WeatherHookReturn {
  formattedTemp: string;
  formattedHumidity: string;
  formattedWind: string;
  conditionIcon: string;
  unitLabel: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const CONDITION_ICON_MAP: Record<string, string> = {
  'Clear': '☀️',
  'Sunny': '☀️',
  'Cloudy': '☁️',
  'Partly Cloudy': '⛅',
  'Mostly Cloudy': '🌥️',
  'Rain': '🌧️',
  'Showers': '🌦️',
  'Thunderstorm': '⛈️',
  'Snow': '❄️',
  'Mist': '🌫️',
  'Fog': '🌫️',
  'Windy': '💨',
};

export const DEFAULT_CONDITION_ICON = '🌡️';

export const UNITS = {
  CELSIUS: 'C',
  FAHRENHEIT: 'F',
} as const;

export const UNIT_SYMBOLS: Record<string, string> = {
  [UNITS.CELSIUS]: '°C',
  [UNITS.FAHRENHEIT]: '°F',
};

export const LABELS = {
  HUMIDITY: 'Humidity',
  WIND_SPEED: 'Wind Speed',
  FORECAST_TITLE: 'Daily Forecast',
  HUMIDITY_UNIT: '%',
  WIND_SPEED_UNIT_METRIC: 'km/h',
  WIND_SPEED_UNIT_IMPERIAL: 'mph',
};

export const DEFAULT_UNIT = UNITS.CELSIUS;


// --- hooks.ts ---
import { useMemo } from 'react';
import type { Props, WeatherHookReturn } from './types';

export function useWeather(props: Props): WeatherHookReturn {
  const { temperature, condition, humidity, windSpeed, unit = 'C' } = props;

  const unitLabel = useMemo(() => {
    return unit === 'F' ? '°F' : '°C';
  }, [unit]);

  const formattedTemp = useMemo(() => {
    return `${Math.round(temperature)}${unitLabel}`;
  }, [temperature, unitLabel]);

  const formattedHumidity = useMemo(() => {
    return `${humidity}%`;
  }, [humidity]);

  const formattedWind = useMemo(() => {
    return `${windSpeed} km/h`;
  }, [windSpeed]);

  const conditionIcon = useMemo(() => {
    const cond = condition.toLowerCase();
    if (cond.includes('sun') || cond.includes('clear')) return 'Sun';
    if (cond.includes('cloud')) return 'Cloud';
    if (cond.includes('rain') || cond.includes('drizzle')) return 'CloudRain';
    if (cond.includes('snow')) return 'Snowflake';
    if (cond.includes('storm') || cond.includes('thunder')) return 'CloudLightning';
    if (cond.includes('wind')) return 'Wind';
    return 'Cloud';
  }, [condition]);

  return {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    conditionIcon,
    unitLabel,
  };
}


