// ForecastDay.tsx — reusable sub-component
import React from 'react';
import { Stack, Text, Icon } from '@ggui-ai/design/primitives';
import type { ForecastDayProps } from './types';

/**
 * ForecastDay renders a single day's forecast in a vertical stack.
 * Displays the day name, weather icon, and the high/low temperature range.
 */
export function ForecastDay({ day, icon, high, low, unit }: ForecastDayProps) {
  return (
    <Stack align="center" gap={8}>
      <Text 
        variant="overline" 
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
        align="center"
      >
        {day}
      </Text>

      <Icon 
        name={icon} 
        size={32} 
        color="var(--ggui-color-primary-600, #0284c7)" 
      />

      <Stack direction="horizontal" gap={4} align="center">
        <Text variant="bodySmall" weight="semibold">
          {Math.round(high)}{unit}
        </Text>
        <Text 
          variant="bodySmall" 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {Math.round(low)}{unit}
        </Text>
      </Stack>
    </Stack>
  );
}


// --- ui.tsx ---
// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { Container, Stack, Heading, Text, Card, Divider, Spacer, Icon } from '@ggui-ai/design/primitives';
import type { Props, WeatherHookReturn } from './types';
import { ForecastDay } from './components';

export function ComponentUI(props: Props & WeatherHookReturn) {
  const {
    city,
    condition,
    forecast,
    formattedTemp,
    formattedHumidity,
    formattedWind,
    unitLabel
  } = props;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
      <Card shadow="md" padding="var(--ggui-spacing-8, 32px)" radius="xl">
        <Stack gap={32} align="center">
          {/* Top Section: City and Temperature */}
          <Stack align="center" gap={8}>
            <Heading level={1} align="center">
              {city}
            </Heading>
            <Stack align="center" gap={4}>
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {formattedTemp}
              </Text>
              <Text
                variant="bodyLarge"
                color="var(--ggui-color-neutral-500, #6b7280)"
              >
                {condition}
              </Text>
            </Stack>
          </Stack>

          {/* Mid Section: Stats Row */}
          <Stack
            direction="horizontal"
            gap={48}
            justify="center"
            align="center"
            style={{ width: '100%' }}
          >
            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                Humidity
              </Text>
              <Text weight="semibold" size="lg">
                {formattedHumidity}
              </Text>
            </Stack>

            <Divider orientation="vertical" margin={8} />

            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                Wind Speed
              </Text>
              <Text weight="semibold" size="lg">
                {formattedWind}
              </Text>
            </Stack>
          </Stack>

          <Divider margin={0} style={{ width: '100%' }} />

          {/* Bottom Section: 5-Day Forecast */}
          <Stack
            direction="horizontal"
            gap={16}
            justify="between"
            wrap
            style={{ width: '100%' }}
          >
            {forecast.map((item, index) => (
              <ForecastDay
                key={`${item.day}-${index}`}
                day={item.day}
                icon={item.icon}
                high={item.high}
                low={item.low}
                unit={unitLabel}
              />
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
